objectives.dqlQuery:
timeseries {
  cpu_throttled_time=avg(dt.containers.cpu.throttled_time)
}, by: {k8s.namespace.name}, filter: {k8s.namespace.name == "staging-astroshop"}
| fields `average throttling/min`=arrayAvg(cpu_throttled_time)/1000000

timeseries {working_mem=avg(dt.kubernetes.container.memory_working_set)}, by:{k8s.container.name}
| filter k8s.container.name == "adservice"
| fields totalMemoryInMb=arrayMax(working_mem)/1000/1000

timeseries {
  cpu_usage=avg(dt.kubernetes.container.cpu_usage)
}, by:{k8s.namespace.name}
| filter contains(k8s.namespace.name,"staging-astroshop")
| fields totalCpuInCores=arraySum(cpu_usage)
